import { AbsoluteFill, useCurrentFrame, useVideoConfig, interpolate } from 'remotion';

const PARAMS = {
  primaryColor: '#0000FF',     // type: color
  speed: 1.0,                  // type: range, min: 0.1, max: 3.0
  duration: 3,                 // type: range, min: 1, max: 10, unit: seconds
} as const;

export const GeneratedAsset = ({
  primaryColor = PARAMS.primaryColor,
  duration = PARAMS.duration,
}: typeof PARAMS = PARAMS) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const totalFrames = duration * fps;
  const count = interpolate(frame, [0, totalFrames], [0, 100], { extrapolateRight: 'clamp' });

  return (
    <AbsoluteFill style={{ backgroundColor: 'transparent', justifyContent: 'center', alignItems: 'center' }}>
      <h1 style={{ color: primaryColor, fontSize: 80 }}>{Math.round(count)}</h1>
    </AbsoluteFill>
  );
};

